175	    it.todo("should sum same-type items into the insurance sum: two swords have insurance sum 2000 and cap 4000");
176	    it.todo("should consume the cap across successive claims: sword (cap 2000) with two claims of 1500 pays 1400 then 600");
177	    it.todo("should round the final payout down to whole gold (350.5 becomes 350)");
