182	    it.todo("should reject a quote containing an unknown item type (broomstick)");
183	    it.todo("should reject a claim damage entry whose item type is not in the policy (amulet damaged, only sword insured)");
184	    it.todo("should reject a claim with more damage entries of a type than items insured (two sword damages, one sword insured)");
185	    it.todo("should reject a claim damage entry with an unknown item type");
