1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: { op: "quote"; items: Item[] }[];
6	};
7	
8	type ScenarioResult = {
9	  results: { premium: number }[];
10	};
11	
12	const PROCESSING_FEE = 5;
13	
14	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
15	
16	const firstInsuranceSurcharge = (premium: number): number =>
17	  premium * FIRST_INSURANCE_SURCHARGE_RATE;
18	
19	const COMPONENT_PREMIUM = 25;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: COMPONENT_PREMIUM,
27	  moonstone: COMPONENT_PREMIUM,
28	};
29	
30	const BLOCK_PREMIUM = 60;
31	
32	const isBlock = (count: number): boolean => count === 3;
33	
34	const countByType = (items: Item[]): Record<string, number> =>
35	  items.reduce<Record<string, number>>((counts, item) => {
36	    counts[item.type] = (counts[item.type] ?? 0) + 1;
37	    return counts;
38	  }, {});
39	
40	const premiumForGroup = (type: string, count: number): number =>
41	  isBlock(count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
42	
43	const basePremiumFor = (items: Item[]): number =>
44	  Object.entries(countByType(items)).reduce(
45	    (total, [type, count]) => total + premiumForGroup(type, count),
46	    0,
47	  );
48	
49	const roundUpToWholeGold = (amount: number): number => Math.ceil(amount);
50	
51	const surchargeFor = (
52	  items: Item[],
53	  qualifies: (item: Item) => boolean,
54	  rate: number,
55	): number =>
56	  items.reduce(
57	    (total, item) =>
58	      total + (qualifies(item) ? BASE_PREMIUMS[item.type] * rate : 0),
59	    0,
60	  );
61	
62	const CURSE_SURCHARGE_RATE = 0.5;
63	
64	const isCursed = (item: Item): boolean => item.cursed === true;
65	
66	const curseSurchargeFor = (items: Item[]): number =>
67	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
68	
69	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
70	
71	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
72	
73	const isHighlyEnchanted = (item: Item): boolean =>
74	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD;
75	
76	const enchantmentSurchargeFor = (items: Item[]): number =>
77	  surchargeFor(items, isHighlyEnchanted, ENCHANTMENT_SURCHARGE_RATE);
78	
79	const quotePremium = (items: Item[]): number => {
80	  const basePremium = basePremiumFor(items);
81	  return roundUpToWholeGold(
82	    basePremium +
83	      curseSurchargeFor(items) +
84	      enchantmentSurchargeFor(items) +
85	      firstInsuranceSurcharge(basePremium) +
86	      PROCESSING_FEE,
87	  );
88	};
89	
90	export const runScenario = (scenario: Scenario): ScenarioResult => ({
91	  results: [{ premium: quotePremium(scenario.steps[0].items) }],
92	});
